// ─── BUTTON ───────────────────────────────────────────────────
function Btn({children,v="primary",onClick,disabled,style={},size="md",full}){
  const [h,setH]=useState(false);
  const pd = size==="lg"?"15px 32px":size==="sm"?"8px 16px":"11px 24px";
  const fs = size==="lg"?17:size==="sm"?13:15;
  const vars = {
    primary:{ background:h?C.navyMid:C.navy, color:C.white, boxShadow:h?shadow.lg:shadow.sm, transform:h?"translateY(-1px)":"none" },
    grad:{ background:C.grad, color:C.white, boxShadow:h?shadow.indigo:shadow.sm, transform:h?"translateY(-1px)":"none" },
    outline:{ background:"transparent", color:C.navy, border:`1.5px solid ${C.border}`, boxShadow:h?shadow.md:"none", transform:h?"translateY(-1px)":"none" },
    ghost:{ background:h?C.bgAlt:"transparent", color:C.textMid },
    white:{ background:h?"#f0f4ff":C.white, color:C.navy, boxShadow:h?shadow.md:shadow.sm, transform:h?"translateY(-1px)":"none" },
    danger:{ background:h?"#dc2626":C.danger, color:C.white, transform:h?"translateY(-1px)":"none" },
    success:{ background:h?"#059669":C.success, color:C.white, transform:h?"translateY(-1px)":"none" },
    warning:{ background:h?"#d97706":C.warning, color:C.white, transform:h?"translateY(-1px)":"none" },
    indigo:{ background:h?"#3451d1":C.indigo, color:C.white, boxShadow:h?shadow.indigo:shadow.sm, transform:h?"translateY(-1px)":"none" },
  };
  return (
    <button disabled={disabled} onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)} onClick={onClick}
      style={{ padding:pd, borderRadius:12, border:"none", cursor:disabled?"not-allowed":"pointer", fontWeight:700, fontSize:fs, fontFamily:"inherit", transition:"all 0.18s", display:"inline-flex", alignItems:"center", gap:8, opacity:disabled?0.6:1, width:full?"100%":"auto", justifyContent:full?"center":"flex-start", ...vars[v], ...style }}>
      {children}
    </button>
  );
}

