const ICON_IMG = "data:image/png;base64,";

function Logo({size="nav",onClick}){
  const iconH = size==="hero"?100:size==="lg"?70:size==="md"?54:32;
  const titleSize = size==="hero"?36:size==="lg"?26:size==="md"?20:16;
  const subSize = size==="hero"?15:size==="lg"?12:size==="md"?11:10;
  return (
    <div onClick={onClick} style={{display:"inline-flex",alignItems:"center",gap:size==="hero"?14:8,cursor:onClick?"pointer":"default"}}>
      <img src={ICON_IMG} alt="ZentriqFlow icon" style={{height:iconH,width:"auto",display:"block"}}/>
      <div>
        <div style={{fontWeight:900,fontSize:titleSize,color:"#0d1b4b",letterSpacing:"-0.5px",lineHeight:1.1,fontFamily:"inherit"}}>ZentriqFlow</div>
        <div style={{fontSize:subSize,color:"#0d1b4b",fontWeight:600,letterSpacing:0.2,lineHeight:1.2,fontFamily:"inherit"}}>No booking. No stress.</div>
      </div>
    </div>
  );
}

function QRImg({url,size=160}){
  return <img src={`https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(url)}`} alt="QR" style={{width:size,height:size,borderRadius:12,border:`1px solid ${C.border}`}} />;
}

