// ─── NAVBAR ───────────────────────────────────────────────────
function Navbar({onNavigate,user,currentView}){
  const [menu,setMenu]=useState(false);
  const [scrolled,setScrolled]=useState(false);
  useEffect(()=>{
    const fn=()=>setScrolled(window.scrollY>10);
    window.addEventListener("scroll",fn);
    return ()=>window.removeEventListener("scroll",fn);
  },[]);
  const links=[
    {label:"Features",view:"home",hash:"features"},
    {label:"How it works",view:"how-it-works"},
    {label:"Pricing",view:"pricing"},
    {label:"Contact",view:"contact"},
  ];
  return (
    <nav style={{...S.nav,boxShadow:scrolled?shadow.sm:"none"}}>
      <div style={S.navInner}>
        <Logo size="nav" onClick={()=>onNavigate("home")} />
        {/* Desktop links */}
        <div style={{display:"flex",alignItems:"center",gap:4,position:"absolute",left:"50%",transform:"translateX(-50%)"}}>
          {links.map(l=>(
            <button key={l.label} onClick={()=>onNavigate(l.view,l.hash)}
              style={{padding:"8px 14px",background:"none",border:"none",cursor:"pointer",fontSize:14,fontWeight:currentView===l.view?700:500,color:currentView===l.view?C.navy:C.textMid,borderRadius:8,transition:"all 0.15s",fontFamily:"inherit"}}
              onMouseEnter={e=>e.currentTarget.style.background=C.bgAlt}
              onMouseLeave={e=>e.currentTarget.style.background="none"}>
              {l.label}
            </button>
          ))}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <Btn v="ghost" onClick={()=>onNavigate(user?"admin":"login")} size="sm">{user?"Dashboard":"Log in"}</Btn>
          <Btn v="primary" onClick={()=>onNavigate(user?"admin":"login")} size="sm">Get started free</Btn>
          {/* Hamburger */}
          <button onClick={()=>setMenu(!menu)} style={{background:"none",border:`1px solid ${C.border}`,borderRadius:10,cursor:"pointer",padding:"8px 10px",display:"flex",flexDirection:"column",gap:4,marginLeft:4}}>
            <span style={{display:"block",width:18,height:2,background:C.navy,borderRadius:2,transition:"all 0.2s",transform:menu?"rotate(45deg) translate(3px,6px)":"none"}} />
            <span style={{display:"block",width:18,height:2,background:C.navy,borderRadius:2,opacity:menu?0:1,transition:"opacity 0.2s"}} />
            <span style={{display:"block",width:18,height:2,background:C.navy,borderRadius:2,transition:"all 0.2s",transform:menu?"rotate(-45deg) translate(3px,-6px)":"none"}} />
          </button>
        </div>
      </div>
      {/* Mobile menu */}
      {menu&&(
        <div style={{position:"fixed",top:68,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.4)",zIndex:99}} onClick={()=>setMenu(false)}>
          <div style={{background:"#fff",padding:"1.5rem",boxShadow:shadow.xl}} onClick={e=>e.stopPropagation()}>
            {[...links,{label:"Log in",view:user?"admin":"login"},{label:"Get started free",view:user?"admin":"login"}].map(l=>(
              <button key={l.label} onClick={()=>{onNavigate(l.view,l.hash);setMenu(false);}}
                style={{display:"block",width:"100%",textAlign:"left",padding:"14px 0",background:"none",border:"none",borderBottom:`1px solid ${C.border}`,cursor:"pointer",fontSize:16,fontWeight:500,color:C.navy,fontFamily:"inherit"}}>
                {l.label}
              </button>
            ))}
          </div>
        </div>
      )}
    </nav>
  );
}

