// ─── LOGIN PAGE ───────────────────────────────────────────────
function LoginPage({onLogin,onNavigate}){
  const [email,setEmail]=useState("");
  const [pw,setPw]=useState("");
  const [loading,setLoading]=useState(false);
  const [error,setError]=useState("");
  const [isSignup,setIsSignup]=useState(false);

  async function submit(){
    if(!email.trim()||!pw.trim()) return setError("Please fill in all fields.");
    setLoading(true); setError("");
    const {data,error:e}=isSignup?await supabase.auth.signUp({email,password:pw}):await supabase.auth.signInWithPassword({email,password:pw});
    setLoading(false);
    if(e){setError(e.message);return;}
    onLogin(data.user);
  }

  return (
    <div style={{...S.app,minHeight:"100vh",background:C.bgAlt,display:"flex",flexDirection:"column"}}>
      <div style={{...S.nav}}><div style={{...S.navInner}}><Logo size="nav" onClick={()=>onNavigate("home")}/><Btn v="ghost" onClick={()=>onNavigate("home")} size="sm">← Back</Btn></div></div>
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"2rem"}}>
        <div style={{...S.card,width:"100%",maxWidth:420,padding:"2.5rem",boxShadow:shadow.xl}}>
          <div style={{textAlign:"center",marginBottom:"2rem"}}>
            <Logo size="lg" />
            <h2 style={{fontSize:24,fontWeight:800,color:C.navy,margin:"1.25rem 0 0.5rem",letterSpacing:"-0.5px"}}>{isSignup?"Create your shop account":"Welcome back"}</h2>
            <p style={S.muted}>{isSignup?"Start managing your queue in minutes":"Sign in to your dashboard"}</p>
          </div>
          {error&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,padding:"12px 16px",marginBottom:16,color:C.danger,fontSize:14,fontWeight:500}}>{error}</div>}
          <label style={S.label}>Email address</label>
          <input style={S.input} type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="you@example.com" onFocus={e=>e.target.style.borderColor=C.indigo} onBlur={e=>e.target.style.borderColor=C.border}/>
          <label style={S.label}>Password</label>
          <input style={S.input} type="password" value={pw} onChange={e=>setPw(e.target.value)} placeholder="••••••••" onKeyDown={e=>e.key==="Enter"&&submit()} onFocus={e=>e.target.style.borderColor=C.indigo} onBlur={e=>e.target.style.borderColor=C.border}/>
          <Btn v="primary" full size="lg" onClick={submit} disabled={loading} style={{marginTop:4}}>{loading?"Please wait…":isSignup?"Create account →":"Sign in →"}</Btn>
          <p style={{...S.muted,textAlign:"center",marginTop:16}}>
            {isSignup?"Already have an account? ":"Don't have an account? "}
            <button onClick={()=>setIsSignup(!isSignup)} style={{background:"none",border:"none",cursor:"pointer",color:C.indigo,fontWeight:700,fontFamily:"inherit",fontSize:14}}>{isSignup?"Sign in":"Sign up free"}</button>
          </p>
        </div>
      </div>
    </div>
  );
}

// ─── BARBER LOGIN ─────────────────────────────────────────────
function BarberLogin({onNavigate}){
  const [shopQuery,setShopQuery]=useState("");
  const [suggestions,setSuggestions]=useState([]);
  const [selectedShop,setSelectedShop]=useState(null);
  const [barbers,setBarbers]=useState([]);
  const [selectedBarber,setSelectedBarber]=useState(null);
  const [pin,setPin]=useState("");
  const [error,setError]=useState("");
  const [loggedIn,setLoggedIn]=useState(null);
  const [showSugg,setShowSugg]=useState(false);

  async function searchShops(q){
    setShopQuery(q);
    setSelectedShop(null);
    if(q.length<2){setSuggestions([]);return;}
    const {data}=await supabase.from("shops").select("id,name,slug").ilike("name",`%${q}%`).limit(6);
    setSuggestions(data||[]);
    setShowSugg(true);
  }

  async function pickShop(shop){
    setSelectedShop(shop); setShopQuery(shop.name); setSuggestions([]); setShowSugg(false);
    const {data}=await supabase.from("barbers").select("*").eq("shop_id",shop.id).eq("is_active",true);
    setBarbers(data||[]);
  }

  function login(){
    if(!selectedShop) return setError("Please select a shop from the suggestions.");
    if(!selectedBarber) return setError("Please select your name.");
    if(!pin.trim()) return setError("Please enter your PIN.");
    if(selectedBarber.pin!==pin) return setError("Incorrect PIN. Please try again.");
    setLoggedIn({barber:selectedBarber,shop:selectedShop});
  }

  if(loggedIn) return <BarberDashboard barber={loggedIn.barber} shop={loggedIn.shop} onLogout={()=>{setLoggedIn(null);setPin("");setSelectedBarber(null);setSelectedShop(null);setShopQuery(""); setBarbers([]);}} onNavigate={onNavigate}/>;

  return (
    <div style={{...S.app,minHeight:"100vh",background:C.bgAlt,display:"flex",flexDirection:"column"}}>
      <div style={S.nav}><div style={S.navInner}><Logo size="nav" onClick={()=>onNavigate("home")}/><Btn v="ghost" onClick={()=>onNavigate("home")} size="sm">← Back</Btn></div></div>
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"2rem"}}>
        <div style={{...S.card,width:"100%",maxWidth:440,padding:"2.5rem",boxShadow:shadow.xl}}>
          <div style={{textAlign:"center",marginBottom:"2rem"}}>
            <div style={{fontSize:48,marginBottom:8}}>✂️</div>
            <h2 style={{fontSize:24,fontWeight:800,color:C.navy,margin:"0 0 0.5rem",letterSpacing:"-0.5px"}}>Barber Login</h2>
            <p style={S.muted}>Sign in to manage your queue</p>
          </div>
          {error&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,padding:"12px 16px",marginBottom:16,color:C.danger,fontSize:14,fontWeight:500}}>{error}</div>}

          {/* Shop search */}
          <label style={S.label}>Your barbershop name</label>
          <div style={{position:"relative",marginBottom:14}}>
            <input style={{...S.input,marginBottom:0}} placeholder="Start typing your shop name…" value={shopQuery} onChange={e=>searchShops(e.target.value)} onFocus={()=>suggestions.length>0&&setShowSugg(true)} onBlur={()=>setTimeout(()=>setShowSugg(false),200)} autoComplete="off"/>
            {showSugg&&suggestions.length>0&&(
              <div style={{position:"absolute",top:"100%",left:0,right:0,background:"#fff",border:`1px solid ${C.border}`,borderRadius:12,boxShadow:shadow.lg,zIndex:50,overflow:"hidden",marginTop:4}}>
                {suggestions.map(s=>(
                  <button key={s.id} onMouseDown={()=>pickShop(s)} style={{display:"block",width:"100%",textAlign:"left",padding:"12px 16px",background:"none",border:"none",borderBottom:`1px solid ${C.border}`,cursor:"pointer",fontFamily:"inherit",fontSize:14,color:C.navy,fontWeight:500}}
                    onMouseEnter={e=>e.currentTarget.style.background=C.bgAlt} onMouseLeave={e=>e.currentTarget.style.background="none"}>
                    <span style={{fontWeight:700}}>{s.name}</span>
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Barber selection */}
          {barbers.length>0&&(
            <>
              <label style={S.label}>Select your name</label>
              <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
                {barbers.map(b=>(
                  <button key={b.id} onClick={()=>{setSelectedBarber(b);setError("");}}
                    style={{display:"flex",alignItems:"center",gap:12,padding:"12px 16px",borderRadius:12,border:`1.5px solid ${selectedBarber?.id===b.id?C.indigo:C.border}`,background:selectedBarber?.id===b.id?C.indigoLight:"#fff",cursor:"pointer",fontFamily:"inherit",transition:"all 0.15s"}}>
                    <div style={{width:36,height:36,borderRadius:"50%",background:C.grad,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,color:"#fff",fontSize:15,flexShrink:0}}>{b.name[0].toUpperCase()}</div>
                    <span style={{fontWeight:600,color:C.navy,fontSize:15}}>{b.name}</span>
                    {selectedBarber?.id===b.id&&<span style={{marginLeft:"auto",color:C.indigo,fontSize:18}}>✓</span>}
                  </button>
                ))}
              </div>
            </>
          )}

          {/* PIN */}
          {selectedBarber&&(
            <>
              <label style={S.label}>Enter your PIN</label>
              <input style={{...S.input,textAlign:"center",fontSize:28,letterSpacing:12,fontWeight:700}} type="password" maxLength={6} placeholder="••••" value={pin} onChange={e=>{setPin(e.target.value);setError("");}} onKeyDown={e=>e.key==="Enter"&&login()} onFocus={e=>e.target.style.borderColor=C.indigo} onBlur={e=>e.target.style.borderColor=C.border}/>
              <Btn v="primary" full size="lg" onClick={login} style={{marginTop:4}}>Sign in →</Btn>
            </>
          )}
          {!selectedBarber&&!barbers.length&&shopQuery.length>1&&(
            <div style={{textAlign:"center",padding:"1.5rem",color:C.textLight,fontSize:14}}>No matching shops found. Check the spelling and try again.</div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── BARBER DASHBOARD ─────────────────────────────────────────
function BarberDashboard({barber,shop,onLogout,onNavigate}){
  const [queue,setQueue]=useState([]);

  const loadQ=useCallback(async()=>{
    const {data}=await supabase.from("queue_entries").select("*,services(name,price,duration)").eq("shop_id",shop.id).eq("barber_id",barber.id).not("status","eq","done").not("status","eq","cancelled").order("position",{ascending:true});
    setQueue(data||[]);
  },[shop.id,barber.id]);

  useEffect(()=>{
    loadQ();
    const ch=supabase.channel("bq-"+barber.id).on("postgres_changes",{event:"*",schema:"public",table:"queue_entries",filter:`shop_id=eq.${shop.id}`},loadQ).subscribe();
    return ()=>supabase.removeChannel(ch);
  },[loadQ,shop.id,barber.id]);

  async function recalc(){
    const {data}=await supabase.from("queue_entries").select("id").eq("shop_id",shop.id).in("status",["waiting","called","on_chair"]).order("position",{ascending:true});
    if(data) for(let i=0;i<data.length;i++) await supabase.from("queue_entries").update({position:i+1}).eq("id",data[i].id);
  }

  async function updateStatus(id,status){
    await supabase.from("queue_entries").update({status,updated_at:new Date().toISOString()}).eq("id",id);
    if(status==="done"){
      const e=queue.find(q=>q.id===id);
      const p=e?.services?.price||0;
      if(p>0) await supabase.rpc("increment_earnings",{barber_id:barber.id,amount:p});
      await recalc();
    }
    loadQ();
  }

  async function callNext(){
    const next=queue.find(q=>q.status==="waiting");
    if(!next) return alert("No customers waiting.");
    await supabase.from("queue_entries").update({status:"called",updated_at:new Date().toISOString()}).eq("id",next.id);
    loadQ();
  }

  const waiting=queue.filter(q=>q.status==="waiting").length;
  const onChair=queue.filter(q=>q.status==="on_chair").length;
  const called=queue.filter(q=>q.status==="called").length;

  return (
    <div style={S.app}>
      <div style={S.nav}><div style={S.navInner}>
        <Logo size="nav" onClick={()=>onNavigate("home")}/>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div style={{textAlign:"right",display:"none"}}><div style={{fontWeight:700,fontSize:14,color:C.navy}}>{barber.name}</div><div style={{fontSize:12,color:C.textLight}}>{shop.name}</div></div>
          <Btn v="outline" size="sm" onClick={onLogout}>Logout</Btn>
        </div>
      </div></div>
      {/* Stats header */}
      <div style={{background:C.gradDark,padding:"1.5rem 0"}}>
        <div style={S.container}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:16,marginBottom:"1rem"}}>
            <div><div style={{color:"rgba(255,255,255,0.6)",fontSize:12,fontWeight:600,marginBottom:2}}>{shop.name}</div><div style={{color:"#fff",fontSize:20,fontWeight:800}}>{barber.name}'s Queue</div></div>
            <Btn v="white" size="sm" onClick={callNext}>📢 Call Next Customer</Btn>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12}}>
            {[{n:waiting,l:"Waiting",c:"#60a5fa"},{n:called,l:"Called",c:"#fbbf24"},{n:onChair,l:"On Chair",c:"#34d399"}].map(s=>(
              <div key={s.l} style={{background:"rgba(255,255,255,0.08)",borderRadius:14,padding:"1rem",textAlign:"center"}}>
                <div style={{fontSize:28,fontWeight:900,color:s.c}}>{s.n}</div>
                <div style={{fontSize:11,color:"rgba(255,255,255,0.5)",marginTop:2}}>{s.l}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
      {/* Queue */}
      <div style={{...S.container,padding:"1.5rem"}}>
        {queue.length===0&&(
          <div style={{...S.card,textAlign:"center",padding:"4rem 2rem",marginTop:8}}>
            <div style={{fontSize:56,marginBottom:16}}>🎉</div>
            <h3 style={{fontSize:18,fontWeight:700,color:C.navy,margin:"0 0 8px"}}>No customers waiting</h3>
            <p style={S.muted}>Customers who choose you will appear here.</p>
          </div>
        )}
        {queue.map(entry=>(
          <div key={entry.id} style={{...S.card,display:"flex",alignItems:"center",gap:14,flexWrap:"wrap",marginBottom:12}}>
            <div style={{width:44,height:44,borderRadius:"50%",background:C.indigoLight,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:16,color:C.indigo,flexShrink:0}}>#{entry.position}</div>
            <div style={{flex:1,minWidth:160}}>
              <div style={{fontWeight:700,fontSize:15,color:C.navy}}>{entry.customer_name}</div>
              <div style={S.muted}>{entry.services?.name}{entry.services?.price?` · £${entry.services.price}`:""} · {fmt(entry.joined_at)}</div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
              <span style={S.badge(STATUS_COLORS[entry.status])}>{STATUS_LABELS[entry.status]}</span>
              {entry.status==="waiting"&&<Btn v="warning" size="sm" onClick={()=>updateStatus(entry.id,"called")}>📢 Call</Btn>}
              {entry.status==="called"&&<Btn v="success" size="sm" onClick={()=>updateStatus(entry.id,"on_chair")}>✓ On Chair</Btn>}
              {entry.status==="on_chair"&&<Btn v="success" size="sm" onClick={()=>updateStatus(entry.id,"done")}>✓ Done</Btn>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}


// ─── CUSTOMER JOIN ────────────────────────────────────────────
function CustomerJoin({shopSlug}){
  const [shop,setShop]=useState(null);
  const [services,setServices]=useState([]);
  const [barbers,setBarbers]=useState([]);
  const [name,setName]=useState("");
  const [phone,setPhone]=useState("");
  const [email,setEmail]=useState("");
  const [serviceId,setServiceId]=useState("");
  const [barberId,setBarberId]=useState("");
  const [loading,setLoading]=useState(false);
  const [joined,setJoined]=useState(null);
  const [errors,setErrors]=useState({});

  useEffect(()=>{
    async function load(){
      const {data:sh}=await supabase.from("shops").select("*").eq("slug",shopSlug).single();
      if(!sh) return;
      setShop(sh);
      const {data:sv}=await supabase.from("services").select("*").eq("shop_id",sh.id);
      setServices(sv||[]);
      if(sv?.length) setServiceId(sv[0].id);
      const {data:b}=await supabase.from("barbers").select("*").eq("shop_id",sh.id).eq("is_active",true);
      setBarbers(b||[]);
    }
    load();
  },[shopSlug]);

  async function joinQueue(){
    const errs={};
    if(!name.trim()) errs.name="Name is required";
    if(!serviceId) errs.service="Please select a service";
    if(Object.keys(errs).length) return setErrors(errs);
    setErrors({});
    const {data:ex}=await supabase.from("queue_entries").select("id").eq("shop_id",shop.id).eq("customer_name",name.trim()).in("status",["waiting","called","on_chair"]);
    if(ex?.length) return alert("You're already in the queue!");
    setLoading(true);
    const {data:pos}=await supabase.from("queue_entries").select("position").eq("shop_id",shop.id).in("status",["waiting","called","on_chair"]).order("position",{ascending:false}).limit(1);
    const nextPos=pos?.length?(pos[0].position||0)+1:1;
    let bid=barberId||null;
    if(!bid&&barbers.length>0){
      const counts=await Promise.all(barbers.map(async b=>{
        const {count}=await supabase.from("queue_entries").select("*",{count:"exact",head:true}).eq("barber_id",b.id).in("status",["waiting","called","on_chair"]);
        return {id:b.id,count:count||0};
      }));
      bid=counts.sort((a,b)=>a.count-b.count)[0].id;
    }
    const {data,error}=await supabase.from("queue_entries").insert({shop_id:shop.id,customer_name:name.trim(),customer_phone:phone.trim(),customer_email:email.trim(),service_id:serviceId,barber_id:bid,status:"waiting",position:nextPos}).select().single();
    setLoading(false);
    if(error){alert("Error: "+error.message);return;}
    setJoined(data);
  }

  if(joined){
    const svc=services.find(s=>s.id===joined.service_id);
    const brb=barbers.find(b=>b.id===joined.barber_id);
    return (
      <div style={{...S.app,minHeight:"100vh",background:C.bgAlt}}>
        <div style={S.nav}><div style={S.navInner}><Logo size="nav"/></div></div>
        <div style={{background:C.grad,padding:"3rem 1.5rem",textAlign:"center"}}>
          <div style={{width:72,height:72,borderRadius:"50%",background:"rgba(255,255,255,0.2)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:32,margin:"0 auto 1rem"}}>✅</div>
          <h2 style={{color:"#fff",fontSize:26,fontWeight:800,margin:"0 0 0.5rem"}}>You're in the queue!</h2>
          <p style={{color:"rgba(255,255,255,0.8)",margin:0}}>{shop?.name}</p>
        </div>
        <div style={{maxWidth:480,margin:"0 auto",padding:"1.5rem"}}>
          <div style={{...S.card,textAlign:"center",padding:"2.5rem",boxShadow:shadow.lg}}>
            <p style={{...S.muted,marginBottom:8,fontSize:13,textTransform:"uppercase",letterSpacing:1,fontWeight:700}}>Your queue number</p>
            <div style={{fontSize:80,fontWeight:900,background:C.grad,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",lineHeight:1}}>#{joined.position}</div>
            <p style={{...S.muted,marginTop:8}}>Joined at {fmt(joined.joined_at)}</p>
          </div>
          <div style={{...S.card,marginTop:16}}>
            <h3 style={{fontSize:16,fontWeight:700,color:C.navy,margin:"0 0 14px"}}>Booking details</h3>
            {[{l:"Name",v:joined.customer_name},{l:"Service",v:svc?.name},{l:"Price",v:svc?`£${svc.price}`:null},{l:"Barber",v:brb?.name}].filter(r=>r.v).map(row=>(
              <div key={row.l} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:`1px solid ${C.border}`}}>
                <span style={S.muted}>{row.l}</span>
                <span style={{fontWeight:600,color:C.navy,fontSize:14}}>{row.v}</span>
              </div>
            ))}
          </div>
          <Btn v="primary" full size="lg" onClick={()=>window.location.href=`/status/${joined.id}`} style={{marginTop:16}}>Track my live position →</Btn>
          <p style={{...S.muted,textAlign:"center",marginTop:12}}>💡 Bookmark the tracking page to check back anytime</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{...S.app,minHeight:"100vh",background:C.bgAlt}}>
      <div style={S.nav}><div style={S.navInner}><Logo size="nav" onClick={()=>window.location.href="/"}/></div></div>
      <div style={{background:C.gradDark,padding:"2.5rem 1.5rem",textAlign:"center"}}>
        <h2 style={{color:"#fff",fontSize:26,fontWeight:800,margin:"0 0 0.5rem",letterSpacing:"-0.5px"}}>Join the queue</h2>
        {shop&&<p style={{color:"rgba(255,255,255,0.6)",margin:0}}>{shop.name}</p>}
      </div>
      <div style={{maxWidth:480,margin:"0 auto",padding:"1.5rem"}}>
        <div style={S.card}>
          <label style={S.label}>Your name *</label>
          <input style={{...S.input,borderColor:errors.name?"#ef4444":C.border}} placeholder="John Smith" value={name} onChange={e=>setName(e.target.value)} onFocus={e=>e.target.style.borderColor=C.indigo} onBlur={e=>e.target.style.borderColor=errors.name?"#ef4444":C.border}/>
          {errors.name&&<p style={{color:C.danger,fontSize:12,marginTop:-10,marginBottom:10}}>{errors.name}</p>}
          <label style={S.label}>Phone number</label>
          <input style={S.input} placeholder="+44 7700 000000" value={phone} onChange={e=>setPhone(e.target.value)} onFocus={e=>e.target.style.borderColor=C.indigo} onBlur={e=>e.target.style.borderColor=C.border}/>
          <label style={S.label}>Email address</label>
          <input style={S.input} type="email" placeholder="john@example.com" value={email} onChange={e=>setEmail(e.target.value)} onFocus={e=>e.target.style.borderColor=C.indigo} onBlur={e=>e.target.style.borderColor=C.border}/>
          <label style={S.label}>Choose a service *</label>
          <select style={{...S.input,cursor:"pointer",borderColor:errors.service?"#ef4444":C.border}} value={serviceId} onChange={e=>setServiceId(e.target.value)}>
            <option value="">Select a service…</option>
            {services.map(s=><option key={s.id} value={s.id}>{s.name} — £{s.price} (~{s.duration}min)</option>)}
          </select>
          {errors.service&&<p style={{color:C.danger,fontSize:12,marginTop:-10,marginBottom:10}}>{errors.service}</p>}
          <label style={S.label}>Preferred barber</label>
          <select style={{...S.input,cursor:"pointer"}} value={barberId} onChange={e=>setBarberId(e.target.value)}>
            <option value="">No preference (auto-assigned)</option>
            {barbers.map(b=><option key={b.id} value={b.id}>{b.name}</option>)}
          </select>
          <Btn v="primary" full size="lg" onClick={joinQueue} disabled={loading} style={{marginTop:4}}>{loading?"Joining…":"Join Queue — No booking needed"}</Btn>
          <p style={{...S.muted,textAlign:"center",marginTop:12}}>You'll get live updates by email</p>
        </div>
      </div>
    </div>
  );
}

// ─── CUSTOMER STATUS ──────────────────────────────────────────
function CustomerStatus({entryId}){
  const [entry,setEntry]=useState(null);
  const [ahead,setAhead]=useState(0);
  const [svc,setSvc]=useState(null);
  const [brb,setBrb]=useState(null);
  const [leaving,setLeaving]=useState(false);

  const load=useCallback(async()=>{
    const {data}=await supabase.from("queue_entries").select("*").eq("id",entryId).single();
    if(!data) return;
    setEntry(data);
    if(data.service_id){const {data:s}=await supabase.from("services").select("*").eq("id",data.service_id).single();setSvc(s);}
    if(data.barber_id){const {data:b}=await supabase.from("barbers").select("*").eq("id",data.barber_id).single();setBrb(b);}
    const {count}=await supabase.from("queue_entries").select("*",{count:"exact",head:true}).eq("shop_id",data.shop_id).eq("status","waiting").lt("position",data.position);
    setAhead(count||0);
  },[entryId]);

  useEffect(()=>{
    load();
    const ch=supabase.channel("st-"+entryId).on("postgres_changes",{event:"UPDATE",schema:"public",table:"queue_entries",filter:`id=eq.${entryId}`},load).subscribe();
    return ()=>supabase.removeChannel(ch);
  },[load,entryId]);

  async function leave(){
    if(!window.confirm("Leave the queue?")) return;
    setLeaving(true);
    await supabase.from("queue_entries").update({status:"cancelled",updated_at:new Date().toISOString()}).eq("id",entryId);
    const {data:rem}=await supabase.from("queue_entries").select("id").eq("shop_id",entry.shop_id).in("status",["waiting","called","on_chair"]).order("position",{ascending:true});
    if(rem) for(let i=0;i<rem.length;i++) await supabase.from("queue_entries").update({position:i+1}).eq("id",rem[i].id);
    setLeaving(false);
    const {data:sh}=await supabase.from("shops").select("slug").eq("id",entry.shop_id).single();
    if(sh) window.location.href=`/shop/${sh.slug}`;
  }

  if(!entry) return <div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh"}}><p>Loading…</p></div>;
  const estWait=svc?ahead*svc.duration:ahead*20;

  if(entry.status==="cancelled") return (
    <div style={{...S.app,minHeight:"100vh",background:C.bgAlt,display:"flex",flexDirection:"column"}}>
      <div style={S.nav}><div style={S.navInner}><Logo size="nav"/></div></div>
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"2rem",textAlign:"center"}}>
        <div><div style={{fontSize:56,marginBottom:16}}>👋</div><h2 style={{fontSize:24,fontWeight:800,color:C.navy,marginBottom:8}}>You've left the queue</h2><p style={S.muted}>Scan the QR code to rejoin anytime.</p></div>
      </div>
    </div>
  );

  return (
    <div style={{...S.app,minHeight:"100vh",background:C.bgAlt}}>
      <div style={S.nav}><div style={S.navInner}><Logo size="nav" onClick={()=>window.location.href="/"}/></div></div>
      <div style={{background:C.gradDark,padding:"2rem 1.5rem",textAlign:"center"}}>
        <span style={S.badge(STATUS_COLORS[entry.status])}>{STATUS_LABELS[entry.status]}</span>
        <h2 style={{color:"#fff",fontSize:24,fontWeight:800,margin:"0.75rem 0 0.25rem"}}>Hey, {entry.customer_name}! 👋</h2>
        <p style={{color:"rgba(255,255,255,0.6)",margin:0,fontSize:13}}>Joined at {fmt(entry.joined_at)}</p>
      </div>
      <div style={{maxWidth:480,margin:"0 auto",padding:"1.5rem"}}>
        {entry.status==="waiting"&&(
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:16}}>
            <div style={{...S.card,textAlign:"center"}}><div style={{fontSize:36,fontWeight:900,color:C.indigo}}>{ahead}</div><div style={{...S.muted,fontSize:12}}>ahead of you</div></div>
            <div style={{...S.card,textAlign:"center"}}><div style={{fontSize:36,fontWeight:900,color:C.navy}}>~{estWait}m</div><div style={{...S.muted,fontSize:12}}>estimated wait</div></div>
          </div>
        )}
        {entry.status==="called"&&(<div style={{...S.card,background:"#fefce8",border:"1px solid #fde047",textAlign:"center",padding:"2rem"}}><div style={{fontSize:40,marginBottom:10}}>🔔</div><h3 style={{fontWeight:800,fontSize:18,color:"#92400e",margin:"0 0 6px"}}>You've been called!</h3><p style={{color:"#b45309",fontSize:14,margin:0}}>Please make your way to the shop now.</p></div>)}
        {entry.status==="on_chair"&&(<div style={{...S.card,background:"#f0fdf4",border:"1px solid #86efac",textAlign:"center",padding:"2rem"}}><div style={{fontSize:40,marginBottom:10}}>✂️</div><h3 style={{fontWeight:800,fontSize:18,color:"#166534",margin:"0 0 6px"}}>You're being served!</h3>{brb&&<p style={{color:"#15803d",fontSize:14,margin:0}}>Barber: {brb.name}</p>}</div>)}
        {entry.status==="done"&&(<div style={{...S.card,textAlign:"center",padding:"2rem"}}><div style={{fontSize:40,marginBottom:10}}>🎉</div><h3 style={{fontWeight:800,fontSize:18,color:C.navy,margin:"0 0 6px"}}>All done — enjoy your fresh cut!</h3><p style={S.muted}>Thanks for visiting. See you next time.</p></div>)}
        <div style={{...S.card,marginTop:16}}>
          <h3 style={{fontSize:15,fontWeight:700,color:C.navy,margin:"0 0 12px"}}>Your booking</h3>
          {[{l:"Service",v:svc?.name},{l:"Barber",v:brb?.name},{l:"Position",v:`#${entry.position}`}].filter(r=>r.v).map(r=>(
            <div key={r.l} style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:`1px solid ${C.border}`}}>
              <span style={S.muted}>{r.l}</span><span style={{fontWeight:600,color:C.navy,fontSize:14}}>{r.v}</span>
            </div>
          ))}
        </div>
        {(entry.status==="waiting"||entry.status==="called")&&(
          <Btn v="danger" full onClick={leave} disabled={leaving} style={{marginTop:12}}>{leaving?"Leaving…":"Leave queue"}</Btn>
        )}
        <p style={{...S.muted,textAlign:"center",marginTop:12,fontSize:12}}>This page updates automatically ✓</p>
      </div>
    </div>
  );
}

// ─── ADMIN DASHBOARD ──────────────────────────────────────────
function AdminDashboard({user,onLogout,onNavigate}){
  const [shop,setShop]=useState(null);
  const [queue,setQueue]=useState([]);
  const [barbers,setBarbers]=useState([]);
  const [services,setServices]=useState([]);
  const [tab,setTab]=useState("queue");
  const [shopName,setShopName]=useState("");
  const [shopSlug,setShopSlug]=useState("");
  const [nBar,setNBar]=useState("");
  const [nBarPin,setNBarPin]=useState("");
  const [nSvcName,setNSvcName]=useState("");
  const [nSvcPrice,setNSvcPrice]=useState("");
  const [nSvcDur,setNSvcDur]=useState("");
  const [copied,setCopied]=useState(false);
  const [showQR,setShowQR]=useState(false);
  const [editSvc,setEditSvc]=useState(null);
  const [editBar,setEditBar]=useState(null);

  const shopUrl=shop?window.location.origin+"/shop/"+shop.slug:"";

  const loadQ=useCallback(async(sid)=>{
    const {data}=await supabase.from("queue_entries").select("*,services(name,price,duration),barbers(name)").eq("shop_id",sid).not("status","eq","done").not("status","eq","cancelled").order("position",{ascending:true});
    setQueue(data||[]);
  },[]);

  useEffect(()=>{
    if(!user) return;
    async function init(){
      const {data:sh}=await supabase.from("shops").select("*").eq("owner_id",user.id).single();
      if(!sh) return;
      setShop(sh); loadQ(sh.id);
      const {data:b}=await supabase.from("barbers").select("*").eq("shop_id",sh.id); setBarbers(b||[]);
      const {data:s}=await supabase.from("services").select("*").eq("shop_id",sh.id); setServices(s||[]);
    }
    init();
  },[user,loadQ]);

  useEffect(()=>{
    if(!shop) return;
    const ch=supabase.channel("adm-"+shop.id).on("postgres_changes",{event:"*",schema:"public",table:"queue_entries",filter:`shop_id=eq.${shop.id}`},()=>loadQ(shop.id)).subscribe();
    return ()=>supabase.removeChannel(ch);
  },[shop,loadQ]);

  async function recalc(sid){
    const {data}=await supabase.from("queue_entries").select("id").eq("shop_id",sid).in("status",["waiting","called","on_chair"]).order("position",{ascending:true});
    if(data) for(let i=0;i<data.length;i++) await supabase.from("queue_entries").update({position:i+1}).eq("id",data[i].id);
  }

  function copyLink(){navigator.clipboard.writeText(shopUrl);setCopied(true);setTimeout(()=>setCopied(false),2000);}

  async function createShop(){
    if(!shopName.trim()||!shopSlug.trim()) return alert("Fill in all fields.");
    const {data,error}=await supabase.from("shops").insert({name:shopName,slug:shopSlug,owner_id:user.id}).select().single();
    if(error){alert(error.message);return;}
    setShop(data);
  }

  async function updateStatus(id,status,bid){
    const u={status,updated_at:new Date().toISOString()};
    if(bid) u.barber_id=bid;
    await supabase.from("queue_entries").update(u).eq("id",id);
    if(status==="done"&&bid){const e=queue.find(q=>q.id===id);const p=e?.services?.price||0;await supabase.rpc("increment_earnings",{barber_id:bid,amount:p});}
    if(status==="done"||status==="cancelled") await recalc(shop.id);
    loadQ(shop.id);
  }

  async function addBarber(){
    if(!nBar.trim()||!nBarPin.trim()) return alert("Fill in all fields.");
    if(nBarPin.length<4) return alert("PIN must be at least 4 digits.");
    const {data}=await supabase.from("barbers").insert({shop_id:shop.id,name:nBar.trim(),pin:nBarPin}).select().single();
    setBarbers([...barbers,data]); setNBar(""); setNBarPin("");
  }

  async function deleteBarber(id){if(!window.confirm("Delete?")) return; await supabase.from("barbers").delete().eq("id",id); setBarbers(barbers.filter(b=>b.id!==id));}

  async function saveBarber(id,name,pin){
    await supabase.from("barbers").update({name:name.trim(),pin}).eq("id",id);
    setBarbers(barbers.map(b=>b.id===id?{...b,name:name.trim(),pin}:b)); setEditBar(null);
  }

  async function toggleBarber(id,isActive){
    await supabase.from("barbers").update({is_active:!isActive}).eq("id",id);
    setBarbers(barbers.map(b=>b.id===id?{...b,is_active:!isActive}:b));
  }

  async function addService(){
    if(!nSvcName.trim()||!nSvcPrice||!nSvcDur) return alert("Fill in all fields.");
    const {error}=await supabase.from("services").insert({shop_id:shop.id,name:nSvcName.trim(),price:parseFloat(nSvcPrice),duration:parseInt(nSvcDur)});
    if(error){alert(error.message);return;}
    const {data:r}=await supabase.from("services").select("*").eq("shop_id",shop.id); setServices(r||[]);
    setNSvcName(""); setNSvcPrice(""); setNSvcDur("");
  }

  async function deleteService(id){if(!window.confirm("Delete?")) return; await supabase.from("services").delete().eq("id",id); setServices(services.filter(s=>s.id!==id));}

  async function saveService(id,name,price,dur){
    await supabase.from("services").update({name:name.trim(),price:parseFloat(price),duration:parseInt(dur)}).eq("id",id);
    setServices(services.map(s=>s.id===id?{...s,name:name.trim(),price:parseFloat(price),duration:parseInt(dur)}:s)); setEditSvc(null);
  }

  async function callNext(){
    const next=queue.find(q=>q.status==="waiting");
    if(!next) return alert("No customers waiting.");
    await supabase.from("queue_entries").update({status:"called",updated_at:new Date().toISOString()}).eq("id",next.id);
    loadQ(shop.id);
  }

  const earn=barbers.reduce((s,b)=>s+(b.daily_earnings||0),0);
  const waiting=queue.filter(q=>q.status==="waiting").length;
  const onChair=queue.filter(q=>q.status==="on_chair").length;
  const called=queue.filter(q=>q.status==="called").length;

  if(!shop) return (
    <div style={{...S.app,minHeight:"100vh",background:C.bgAlt}}>
      <div style={S.nav}><div style={S.navInner}><Logo size="nav" onClick={()=>onNavigate("home")}/><Btn v="outline" size="sm" onClick={onLogout}>Logout</Btn></div></div>
      <div style={{maxWidth:480,margin:"3rem auto",padding:"0 1.5rem"}}>
        <div style={{...S.card,padding:"2.5rem"}}>
          <h2 style={{fontSize:22,fontWeight:800,color:C.navy,margin:"0 0 0.5rem"}}>Set up your shop</h2>
          <p style={{...S.muted,marginBottom:"1.5rem"}}>Create your shop to get started with ZentriqFlow.</p>
          <label style={S.label}>Shop name</label>
          <input style={S.input} placeholder="The Barber Shop" value={shopName} onChange={e=>setShopName(e.target.value)}/>
          <label style={S.label}>URL slug (no spaces)</label>
          <input style={S.input} placeholder="my-barber-shop" value={shopSlug} onChange={e=>setShopSlug(e.target.value.toLowerCase().replace(/\s+/g,"-"))}/>
          <p style={{...S.muted,marginBottom:"1rem"}}>Customer link: <strong style={{color:C.navy}}>/shop/{shopSlug||"your-slug"}</strong></p>
          <Btn v="primary" full size="lg" onClick={createShop}>Create Shop →</Btn>
        </div>
      </div>
    </div>
  );

  return (
    <div style={S.app}>
      <div style={S.nav}><div style={S.navInner}>
        <Logo size="nav" onClick={()=>onNavigate("home")}/>
        <div style={{fontWeight:600,color:C.navy,fontSize:15,position:"absolute",left:"50%",transform:"translateX(-50%)"}}>{shop.name}</div>
        <Btn v="outline" size="sm" onClick={onLogout}>Logout</Btn>
      </div></div>

      {/* Stats */}
      <div style={{background:C.gradDark,padding:"1.5rem 0"}}>
        <div style={S.container}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(100px,1fr))",gap:12}}>
            {[{n:waiting,l:"Waiting",c:"#60a5fa"},{n:called,l:"Called",c:"#fbbf24"},{n:onChair,l:"On Chair",c:"#34d399"},{n:`£${earn.toFixed(0)}`,l:"Today",c:"#a78bfa"}].map(s=>(
              <div key={s.l} style={{background:"rgba(255,255,255,0.08)",borderRadius:14,padding:"1rem",textAlign:"center"}}>
                <div style={{fontSize:26,fontWeight:900,color:s.c}}>{s.n}</div>
                <div style={{fontSize:11,color:"rgba(255,255,255,0.5)",marginTop:2}}>{s.l}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div style={S.container}>
        {/* Link card */}
        <div style={{...S.card,margin:"1.5rem 0",display:"flex",alignItems:"center",gap:14,flexWrap:"wrap"}}>
          <div style={{flex:1,minWidth:200}}><div style={{fontWeight:700,color:C.navy,marginBottom:2}}>Customer join link</div><div style={{...S.muted,wordBreak:"break-all",fontSize:13}}>{shopUrl}</div></div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            <Btn v="indigo" size="sm" onClick={copyLink}>{copied?"✓ Copied!":"Copy link"}</Btn>
            <Btn v="outline" size="sm" onClick={()=>setShowQR(!showQR)}>{showQR?"Hide QR":"Show QR"}</Btn>
          </div>
        </div>
        {showQR&&<div style={{...S.card,textAlign:"center",padding:"2rem",marginBottom:"1.5rem"}}><QRImg url={shopUrl} size={200}/><p style={{...S.muted,marginTop:12}}>Display this QR code at your shop</p></div>}

        {/* Tabs */}
        <div style={{display:"flex",borderBottom:`2px solid ${C.border}`,marginBottom:"1.5rem"}}>
          {["queue","barbers","services"].map(t=><button key={t} style={S.tab(tab===t)} onClick={()=>setTab(t)}>{t==="queue"?`Queue (${queue.length})`:t.charAt(0).toUpperCase()+t.slice(1)}</button>)}
        </div>

        {/* Queue Tab */}
        {tab==="queue"&&(
          <div>
            <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16,flexWrap:"wrap"}}>
              <Btn v="indigo" size="md" onClick={callNext}>📢 Call Next Customer</Btn>
              <span style={S.muted}>{waiting} waiting · {onChair} on chair</span>
            </div>
            {queue.length===0&&<div style={{...S.card,textAlign:"center",padding:"3rem",background:C.bgAlt,border:"1px dashed "+C.border}}><div style={{fontSize:40,marginBottom:12}}>📭</div><h3 style={{fontSize:16,fontWeight:700,color:C.navy,marginBottom:8}}>Queue is empty</h3><p style={S.muted}>Share your link and customers will appear here.</p></div>}
            {queue.map(entry=>(
              <div key={entry.id} style={{...S.card,display:"flex",alignItems:"center",gap:14,flexWrap:"wrap",marginBottom:12,boxShadow:shadow.sm}}>
                <div style={{width:44,height:44,borderRadius:"50%",background:C.indigoLight,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:15,color:C.indigo,flexShrink:0}}>#{entry.position}</div>
                <div style={{flex:1,minWidth:160}}>
                  <div style={{fontWeight:700,fontSize:15,color:C.navy}}>{entry.customer_name}</div>
                  <div style={S.muted}>{entry.services?.name} · {fmt(entry.joined_at)}{entry.barbers?` · ${entry.barbers.name}`:""}</div>
                </div>
                <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                  <span style={S.badge(STATUS_COLORS[entry.status])}>{STATUS_LABELS[entry.status]}</span>
                  {entry.status==="called"&&<Btn v="success" size="sm" onClick={()=>updateStatus(entry.id,"on_chair",entry.barber_id)}>✓ On Chair</Btn>}
                  {entry.status==="on_chair"&&<Btn v="success" size="sm" onClick={()=>updateStatus(entry.id,"done",entry.barber_id)}>✓ Mark done</Btn>}
                  {entry.status==="waiting"&&<Btn v="danger" size="sm" onClick={()=>updateStatus(entry.id,"cancelled")}>Cancel</Btn>}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Barbers Tab */}
        {tab==="barbers"&&(
          <div>
            <div style={{...S.card,background:C.indigoLight,border:`1px solid ${C.indigo}25`,marginBottom:16}}><p style={{...S.muted,margin:0}}>💡 Barbers log in at <strong>zentriqflow.com/barber</strong> using their shop name and PIN.</p></div>
            {barbers.map(b=>(
              <div key={b.id} style={{...S.card,display:"flex",alignItems:"center",gap:14,flexWrap:"wrap",marginBottom:12}}>
                <div style={{width:40,height:40,borderRadius:"50%",background:C.grad,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,fontSize:15,color:"#fff",flexShrink:0}}>{b.name[0].toUpperCase()}</div>
                {editBar===b.id?(
                  <div style={{flex:1}}>
                    <input style={S.input} defaultValue={b.name} id={`bn-${b.id}`} placeholder="Name"/>
                    <input style={S.input} defaultValue={b.pin||""} id={`bp-${b.id}`} placeholder="PIN" maxLength={6}/>
                    <div style={{display:"flex",gap:8}}><Btn v="success" size="sm" onClick={()=>saveBarber(b.id,document.getElementById(`bn-${b.id}`).value,document.getElementById(`bp-${b.id}`).value)}>Save</Btn><Btn v="ghost" size="sm" onClick={()=>setEditBar(null)}>Cancel</Btn></div>
                  </div>
                ):(
                  <><div style={{flex:1}}><div style={{fontWeight:700,color:C.navy}}>{b.name}</div><div style={S.muted}>PIN: {b.pin?"••••":<span style={{color:C.danger}}>Not set</span>} · Today: <strong style={{color:C.navy}}>£{(b.daily_earnings||0).toFixed(2)}</strong></div></div>
                  <span style={S.badge(b.is_active?C.success:"#64748b")}>{b.is_active?"Active":"Off"}</span>
                  <Btn v="ghost" size="sm" onClick={()=>toggleBarber(b.id,b.is_active)}>{b.is_active?"Deactivate":"Activate"}</Btn>
                  <Btn v="ghost" size="sm" onClick={()=>setEditBar(b.id)}>Edit</Btn>
                  <Btn v="danger" size="sm" onClick={()=>deleteBarber(b.id)}>Delete</Btn></>
                )}
              </div>
            ))}
            <div style={S.card}>
              <h3 style={{fontSize:16,fontWeight:700,color:C.navy,margin:"0 0 14px"}}>Add a barber</h3>
              <label style={S.label}>Name</label><input style={S.input} placeholder="Barber name" value={nBar} onChange={e=>setNBar(e.target.value)}/>
              <label style={S.label}>PIN (4–6 digits)</label><input style={S.input} placeholder="1234" maxLength={6} value={nBarPin} onChange={e=>setNBarPin(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addBarber()}/>
              <Btn v="indigo" onClick={addBarber}>Add Barber</Btn>
            </div>
          </div>
        )}

        {/* Services Tab */}
        {tab==="services"&&(
          <div>
            {services.map(s=>(
              <div key={s.id} style={{...S.card,display:"flex",alignItems:"center",gap:14,marginBottom:12}}>
                {editSvc===s.id?(
                  <div style={{flex:1}}>
                    <input style={S.input} defaultValue={s.name} id={`sn-${s.id}`}/>
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                      <input style={S.input} defaultValue={s.price} id={`sp-${s.id}`} type="number" placeholder="Price"/>
                      <input style={S.input} defaultValue={s.duration} id={`sd-${s.id}`} type="number" placeholder="Duration"/>
                    </div>
                    <div style={{display:"flex",gap:8}}><Btn v="success" size="sm" onClick={()=>saveService(s.id,document.getElementById(`sn-${s.id}`).value,document.getElementById(`sp-${s.id}`).value,document.getElementById(`sd-${s.id}`).value)}>Save</Btn><Btn v="ghost" size="sm" onClick={()=>setEditSvc(null)}>Cancel</Btn></div>
                  </div>
                ):(
                  <><div style={{flex:1}}><div style={{fontWeight:700,color:C.navy}}>{s.name}</div><div style={S.muted}>{s.duration} min</div></div>
                  <span style={{fontWeight:800,color:C.navy,fontSize:17}}>£{s.price}</span>
                  <Btn v="ghost" size="sm" onClick={()=>setEditSvc(s.id)}>Edit</Btn>
                  <Btn v="danger" size="sm" onClick={()=>deleteService(s.id)}>Delete</Btn></>
                )}
              </div>
            ))}
            <div style={S.card}>
              <h3 style={{fontSize:16,fontWeight:700,color:C.navy,margin:"0 0 14px"}}>Add a service</h3>
              <label style={S.label}>Service name</label><input style={S.input} placeholder="Skin Fade" value={nSvcName} onChange={e=>setNSvcName(e.target.value)}/>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <div><label style={S.label}>Price (£)</label><input style={S.input} type="number" placeholder="25" value={nSvcPrice} onChange={e=>setNSvcPrice(e.target.value)}/></div>
                <div><label style={S.label}>Duration (min)</label><input style={S.input} type="number" placeholder="30" value={nSvcDur} onChange={e=>setNSvcDur(e.target.value)}/></div>
              </div>
              <Btn v="indigo" onClick={addService}>Add Service</Btn>
            </div>
          </div>
        )}
        <div style={{height:40}}/>
      </div>
    </div>
  );
}

// ─── ROOT APP ─────────────────────────────────────────────────
export default function App(){
  const [view,setView]=useState("home");
  const [shopSlug,setShopSlug]=useState(null);
  const [entryId,setEntryId]=useState(null);
  const [user,setUser]=useState(null);

  function navigate(v,hash){
    setView(v);
    if(hash) setTimeout(()=>document.getElementById(hash)?.scrollIntoView({behavior:"smooth"}),100);
    window.scrollTo({top:0,behavior:"smooth"});
  }

  useEffect(()=>{
    const path=window.location.pathname;
    const sm=path.match(/\/shop\/([^/]+)/);
    const stm=path.match(/\/status\/([^/]+)/);
    const bm=path.match(/\/barber/);
    if(sm){setShopSlug(sm[1]);setView("join");}
    else if(stm){setEntryId(stm[1]);setView("status");}
    else if(bm){setView("barber-login");}
    supabase.auth.getUser().then(({data})=>{if(data.user) setUser(data.user);});
  },[]);

  if(view==="join"&&shopSlug) return <CustomerJoin shopSlug={shopSlug}/>;
  if(view==="status"&&entryId) return <CustomerStatus entryId={entryId}/>;
  if(view==="barber-login") return <BarberLogin onNavigate={navigate}/>;
  if(view==="admin") return <AdminDashboard user={user} onLogout={()=>{supabase.auth.signOut();setView("home");setUser(null);}} onNavigate={navigate}/>;
  if(view==="login") return <LoginPage onLogin={(u)=>{setUser(u);navigate("admin");}} onNavigate={navigate}/>;
  if(view==="how-it-works") return <HowItWorksPage onNavigate={navigate} user={user}/>;
  if(view==="faq") return <FaqPage onNavigate={navigate} user={user}/>;
  if(view==="contact") return <ContactPage onNavigate={navigate} user={user}/>;
  if(view==="privacy") return <PrivacyPage onNavigate={navigate} user={user}/>;
  if(view==="terms") return <TermsPage onNavigate={navigate} user={user}/>;
  if(view==="pricing") return <PricingPage onNavigate={navigate} user={user}/>;
  return <HeroPage onNavigate={navigate} user={user}/>;
}
